.calendar-container {
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  padding: 0.142em;
  /* ~2px */
  box-sizing: border-box;
  width: 100%;
  height: 100%;
  overflow-y: auto;
  /* We map font-size from a container variable if available, else 14px */
  font-size: var(--base-font-size, 14px);
}
.calendar-header {
  display: flex;
  gap: 0.571em;
  /* 8px */
  margin-bottom: 0.357em;
  /* ~5px */
}
.calendar-container.btns-right .calendar-header {
  justify-content: flex-end;
}
.calendar-container.btns-right #btn-collapse {
  order: 4;
}
.calendar-container.btns-right #btn-toggle-blocks {
  order: 3;
}
.calendar-container.btns-right #btn-view-switch {
  order: 2;
}
.calendar-container.btns-right #btn-reset {
  order: 1;
}
.btn-icon {
  background: #ffffff;
  border: 1px solid #d1d5db;
  border-radius: 0.357em;
  /* 5px */
  padding: 0.142em;
  /* ~2px */
  cursor: pointer;
  font-size: 1.14em;
  /* 16px */
  color: #4b5563;
  /* dark-gray */
  transition: background 0.2s, color 0.2s, border-color 0.2s;
  display: flex;
  align-items: center;
  justify-content: center;
  line-height: 0;
}
.btn-icon svg {
  display: block;
}
.btn-icon:hover:not(:disabled) {
  background: #f3f4f6;
  border-color: #9ca3af;
  color: #111827;
}
.btn-icon:disabled {
  opacity: 0.3;
  cursor: not-allowed;
}
.main-panel {
  border: var(--container-border-weight, 1px) solid var(--container-border-color, #e5e7eb);
  border-radius: 0.571em;
  /* 8px */
  background: #ffffff;
  box-shadow: 0 0.285em 0.428em -0.071em rgba(0, 0, 0, 0.1);
  /* 4px 6px 1px */
  transition: max-height 0.3s ease, opacity 0.3s ease, border-color 0.3s ease, box-shadow 0.3s ease;
  overflow: hidden;
  max-height: 71.42em;
  /* 1000px */
  opacity: 1;
}
.main-panel.collapsed {
  max-height: 0;
  opacity: 0;
  border-color: transparent;
  box-shadow: none;
}
.empty-state {
  padding: 1.42em;
  /* 20px */
  text-align: center;
  color: #6b7280;
  font-size: 1em;
  /* 14px */
}
.calendar-block {
  border-bottom: 1px solid #f3f4f6;
  transition: background 0.2s ease;
}
.calendar-block:hover {
  background: #f3f4f6;
}
.block-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.142em 1.14em;
  /* ~2px 16px */
  cursor: pointer;
  background: #ffffff;
  transition: background 0.2s;
}
.block-header:hover {
  background: #f9fafb;
}
.block-title {
  font-size: 0.857em;
  /* 12px */
  font-weight: 600;
  text-transform: uppercase;
  color: #4b5563;
  letter-spacing: 0.05em;
}
.icon {
  color: #9ca3af;
  font-size: 0.857em;
  /* 12px */
}
.block-content {
  display: flex;
  gap: 0.714em;
  /* 10px */
  padding: 0.142em 1.42em;
  /* ~2px 20px */
  overflow-x: auto;
  transition: max-height 0.3s ease, padding 0.3s ease, opacity 0.3s ease;
  max-height: 14.28em;
  /* 200px */
  opacity: 1;
  scrollbar-width: thin;
}
.block-content.collapsed {
  max-height: 0;
  padding-top: 0;
  padding-bottom: 0;
  opacity: 0;
  overflow: hidden;
}
.block-content::-webkit-scrollbar {
  height: 0.428em;
  /* 6px */
}
.block-content::-webkit-scrollbar-thumb {
  background-color: #d1d5db;
  border-radius: 0.214em;
  /* 3px */
}
.block-item {
  border: 1px solid #e5e7eb;
  border-radius: 0.428em;
  /* 6px */
  padding: 0.428em 0.857em;
  /* 6px 12px */
  font-size: 0.928em;
  /* 13px */
  color: #374151;
  white-space: nowrap;
  cursor: pointer;
  background: #f9fafb;
  transition: all 0.2s;
}
.block-item:hover {
  background: #ebf8ff;
  border-color: #90cdf4;
  color: #2b6cb0;
}
.block-item.selected {
  background-color: var(--accent-color, #3b82f6);
  color: white;
  border-color: var(--accent-color, #3b82f6);
}
.dates-block {
  padding: 0.285em 1.14em;
  /* ~4px 16px */
  background: var(--dates-bg-color, #fafafa);
  display: flex;
  flex-direction: column;
  gap: 0.285em;
  /* ~4px */
}
.dates-block.dates-disabled {
  opacity: 0.4;
  pointer-events: none;
}
.dates-inputs {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.714em;
  /* 10px */
  width: 100%;
}
.dates-inputs input[type="date"] {
  flex: 1;
  min-width: 0;
  width: 0;
  padding: 0.571em 0.857em;
  /* 8px 12px */
  border: 1px solid #d1d5db;
  border-radius: 0.428em;
  /* 6px */
  font-family: inherit;
  font-size: 1em;
  /* 14px */
  color: #111827;
  background: #ffffff;
  cursor: pointer;
}
.dates-inputs input[type="date"]:focus {
  outline: none;
  border-color: #3b82f6;
  box-shadow: 0 0 0 0.214em rgba(59, 130, 246, 0.2);
  /* 3px */
}
.separator {
  color: #9ca3af;
  font-weight: 300;
}
@keyframes toggleFlip {
  0% {
    transform: scale(0.5);
    opacity: 0;
  }
  100% {
    transform: scale(1);
    opacity: 1;
  }
}
.animate-flip {
  animation: toggleFlip 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}
.filter-status {
  flex: 1;
  padding: 0.142em 0.571em;
  /* ~2px 8px — matches btn-icon padding/height */
  font-size: 0.785em;
  /* 11px */
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: #9ca3af;
  background: #ffffff;
  border: 1px solid #d1d5db;
  border-radius: 0.357em;
  /* 5px — matches btn-icon */
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: color 0.2s;
}
.filter-status.active {
  color: var(--accent-color, #3b82f6);
}
.calendar-container.btns-right .filter-status {
  order: 0;
  justify-content: center;
}
